import { isFunction, round } from 'lodash-es';
import { useMemo, type CSSProperties } from 'react';

import { container } from './InnerDonut.sty.js';
import { Flex } from '../../../../../../layouts/flex/Flex.js';
import { useChartInnerElement } from '../../../../context/InnerElementContext.js';
import { useVisibleSlicesState } from '../../../../hooks/store/selectors.js';
import type { InnerWrapperProps } from '../../../../types/internal/pie-chart.js';
import { buildCumulativeValues } from '../../../../utils/build-cumulative-value.js';

interface InnerDonutProps extends Pick<InnerWrapperProps, 'visibleIds'> {
  donutInner: number;
}

export const InnerDonut = ({ donutInner, visibleIds }: InnerDonutProps) => {
  const { innerElement } = useChartInnerElement();
  const visibleSlices = useVisibleSlicesState();

  const { absoluteValue, relativeValue } = useMemo(
    () => buildCumulativeValues(visibleSlices, visibleIds),
    [visibleIds, visibleSlices],
  );

  if (!innerElement) {
    return null;
  }

  const containerStyle: CSSProperties = {
    width: `${donutInner}px`,
    height: `${donutInner}px`,
  };

  return (
    <Flex
      justifyContent="center"
      alignItems="center"
      className={container}
      style={containerStyle}
    >
      {isFunction(innerElement)
        ? innerElement({
            absoluteValue,
            relativeValue: round(relativeValue, 2),
            dimensions: { width: donutInner, height: donutInner },
          })
        : innerElement}
    </Flex>
  );
};
